import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../api/client';
import ToastMessage from '../components/ToastMessage';

function Register() {
  const navigate = useNavigate();
  const [form, setForm] = useState({ name: '', email: '', password: '' });
  const [msg, setMsg] = useState('');
  const [error, setError] = useState('');

  const submit = async (e) => {
    e.preventDefault();
    setMsg('');
    setError('');
    try {
      await api.post('/auth/register', form);
      setMsg('Registration successful. Please login.');
      setTimeout(() => navigate('/login'), 900);
    } catch (err) {
      setError(err.response?.data?.error || 'Registration failed');
    }
  };

  return (
    <div className="container py-5">
      <div className="row justify-content-center">
        <div className="col-md-5">
          <div className="card p-4 shadow-sm">
            <h3 className="mb-3 text-center">Register</h3>
            <form onSubmit={submit}>
              <input className="form-control mb-3" placeholder="Name"
                value={form.name} onChange={(e) => setForm({ ...form, name: e.target.value })} />
              <input className="form-control mb-3" placeholder="Email" type="email"
                value={form.email} onChange={(e) => setForm({ ...form, email: e.target.value })} />
              <input className="form-control mb-3" placeholder="Password" type="password"
                value={form.password} onChange={(e) => setForm({ ...form, password: e.target.value })} />
              <button className="btn btn-danger w-100" type="submit">Create Account</button>
            </form>
            <ToastMessage message={msg} />
            <ToastMessage message={error} type="danger" />
          </div>
        </div>
      </div>
    </div>
  );
}

export default Register;
